const Navbar = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const location = useLocation();

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 40);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    if (isOpen) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = 'unset';
    }
  }, [isOpen]);

  const navClass = scrolled 
    ? 'bg-white shadow-xl py-3 border-b border-slate-200' 
    : 'bg-slate-900/80 backdrop-blur-lg py-5 border-b border-white/10';

  const linkBaseColor = scrolled ? 'text-slate-700' : 'text-slate-100';

  return (
    <>
      <TopBar />
      <nav className={`fixed w-full z-50 transition-all duration-300 ${navClass} ${scrolled ? 'top-0' : 'lg:top-10 top-0'}`}>
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center">
            <Link to="/" className="flex items-center" aria-label="Promarch Consulting Home">
              <Logo className="h-10 md:h-12" isDark={!scrolled} />
            </Link>

            {/* Desktop Menu */}
            <div className="hidden md:flex space-x-8 items-center">
              {NAV_LINKS.map((link) => (
                <Link
                  key={link.href}
                  to={link.href}
                  className={`text-sm font-bold tracking-wide transition-all relative py-1 group ${
                    location.pathname === link.href ? '' : linkBaseColor
                  }`}
                  style={location.pathname === link.href ? { color: COLORS.primary } : {}}
                >
                  {link.label}
                  <span 
                    className={`absolute bottom-0 left-0 w-full h-0.5 transition-transform duration-300 transform scale-x-0 group-hover:scale-x-100 ${location.pathname === link.href ? 'scale-x-100' : ''}`}
                    style={{ backgroundColor: COLORS.primary }}
                  ></span>
                </Link>
              ))}
              <Link 
                to="/hire-talent" 
                className={`px-6 py-2.5 rounded-xl text-sm font-black transition-all transform hover:-translate-y-0.5 shadow-lg flex items-center gap-2 ${
                  scrolled ? 'text-white' : 'bg-white text-slate-900 hover:bg-slate-50'
                }`}
                style={scrolled ? { backgroundColor: COLORS.primary } : {}}
              >
                Hire Talent
              </Link>
            </div>

            {/* Mobile Toggle */}
            <button 
              className={`md:hidden p-2.5 rounded-xl transition-colors ${scrolled ? 'bg-slate-100 text-slate-900' : 'bg-white/10 text-white'}`}
              onClick={() => setIsOpen(!isOpen)}
              aria-label={isOpen ? "Close menu" : "Open menu"}
            >
              {isOpen ? <X size={24} /> : <Menu size={24} />}
            </button>
          </div>
        </div>

        {/* Mobile Fullscreen Menu */}
        <div 
          className={`fixed inset-0 bg-[#0f172a] transition-all duration-500 md:hidden ${
            isOpen ? 'opacity-100 translate-x-0' : 'opacity-0 translate-x-full'
          }`}
          style={{ zIndex: 100 }}
        >
          <div className="flex flex-col h-full p-8">
            <div className="flex justify-between items-center mb-12">
              <Logo className="h-10" isDark={true} />
              <button onClick={() => setIsOpen(false)} className="text-white p-2 bg-white/10 rounded-full">
                <X size={28} />
              </button>
            </div>

            <div className="flex flex-col space-y-4">
              {NAV_LINKS.map((link) => (
                <Link
                  key={link.href}
                  to={link.href}
                  onClick={() => setIsOpen(false)}
                  className={`text-4xl font-black flex items-center justify-between group py-2 transition-all ${
                    location.pathname === link.href ? 'pl-4 border-l-4' : 'text-slate-100 hover:pl-2'
                  }`}
                  style={location.pathname === link.href ? { color: COLORS.secondary, borderColor: COLORS.secondary } : {}}
                >
                  {link.label}
                  <ChevronRight size={24} />
                </Link>
              ))}
            </div>

            <div className="mt-auto pt-12 border-t border-slate-800">
              <div className="flex flex-col space-y-4 mb-10">
                <div className="flex items-center space-x-3 text-slate-300">
                  <Phone size={18} style={{ color: COLORS.secondary }} />
                  <span className="font-bold">{COMPANY_PHONE}</span>
                </div>
                <div className="flex items-center space-x-3 text-slate-300">
                  <Mail size={18} style={{ color: COLORS.secondary }} />
                  <span className="text-sm">{COMPANY_EMAIL}</span>
                </div>
              </div>

              <Link 
                to="/hire-talent"
                className="w-full text-white text-center py-5 rounded-2xl font-black text-xl shadow-xl transition-transform active:scale-95"
                style={{ backgroundColor: COLORS.primary }}
                onClick={() => setIsOpen(false)}
              >
                Hire Talent
              </Link>
            </div>
          </div>
        </div>
      </nav>
    </>
  );
};

