                  ></span>
                </Link>
              ))}
              <Link 
                to="/hire-talent" 
                className={`px-6 py-2.5 rounded-xl text-sm font-black transition-all transform hover:-translate-y-0.5 shadow-lg flex items-center gap-2 ${
