                  <span className="font-bold">{COMPANY_PHONE}</span>
                </div>
                <div className="flex items-center space-x-3 text-slate-600">
                  <Mail size={18} className="text-blue-600" />
                  <span className="text-sm">{COMPANY_EMAIL}</span>
                </div>
