    setDebugUrl(absoluteUrl);

    try {
      const response = await fetch(targetPath);

      // DIAGNOSTIC 1: Check if file exists (404 Error)
      if (response.status === 404) {
        throw { 
          type: '404', 
          message: "The file '/api/get_messages.php' was not found on the server." 
        };
      }

      // DIAGNOSTIC 2: Check for Server Errors (500 Error - usually server misconfiguration)
      if (response.status === 500) {
        throw { 
          type: '500', 
          message: "Internal Server Error. The PHP script crashed." 
        };
      }

      const text = await response.text();

      // DIAGNOSTIC 3: Check if response is valid JSON
      let data;
      try {
        data = JSON.parse(text);
      } catch (e) {
        const preview = text.substring(0, 100).replace(/<[^>]*>?/gm, '');
        throw { 
          type: 'json', 
