import React, { useEffect, useState } from 'react';
import { Loader2, AlertCircle, RefreshCw, Mail, Calendar, Info, CheckCircle, ServerCrash, FileQuestion, Lock, ExternalLink, Globe, Settings, Save } from 'lucide-react';

interface Message {
  id: number;
  name: string;
  email: string;
  subject: string;
  message: string;
  created_at: string;
}

// Sample data to show when API is not connected
const MOCK_MESSAGES: Message[] = [
  {
    id: 101,
    name: "Sarah Williams",
    email: "sarah.w@carehome-london.co.uk",
    subject: "Hiring Staff",
    message: "We urgently need 3 qualified nurses for night shifts starting next week. Please contact us to discuss rates.",
    created_at: new Date(Date.now() - 1000 * 60 * 60 * 2).toISOString()
  },
  {
    id: 102,
    name: "James Miller",
    email: "james@logistics-solutions.com",
    subject: "Partnership Inquiry",
    message: "Hi, we are a logistics firm looking to partner with a reliable agency for seasonal warehouse staff.",
    created_at: new Date(Date.now() - 1000 * 60 * 60 * 24).toISOString()
  },
  {
    id: 103,
    name: "David Chen",
    email: "david.c@email.com",
    subject: "Looking for a Job",
    message: "I am a forklift driver with 5 years experience looking for immediate work in East London. Attached is my CV details...",
    created_at: new Date(Date.now() - 1000 * 60 * 60 * 48).toISOString()
  }
];

const AdminDashboard: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [loading, setLoading] = useState(true);
  const [errorDetails, setErrorDetails] = useState<{ type: '404' | 'cors' | 'file_missing' | '500' | 'json' | 'db_auth' | 'unknown', message: string } | null>(null);
  const [isDemoMode, setIsDemoMode] = useState(false);
  const [debugUrl, setDebugUrl] = useState<string>('');

  // New state for handling remote API connection
  const [apiHost, setApiHost] = useState<string>(() => localStorage.getItem('api_host') || '');
  const [isDevEnvironment, setIsDevEnvironment] = useState(false);
  const [showConfig, setShowConfig] = useState(false);

  useEffect(() => {
    // Detect if running in a dev environment (localhost, stackblitz, google idx, etc)
    const hostname = window.location.hostname;
    if (hostname.includes('localhost') || hostname.includes('google') || hostname.includes('webcontainer') || hostname.includes('sandbox')) {
      setIsDevEnvironment(true);
      if (!apiHost) setShowConfig(true);
    }
  }, []);

  const saveApiHost = (host: string) => {
    // Remove trailing slash if present
    const cleanHost = host.replace(/\/$/, '');
    setApiHost(cleanHost);
    localStorage.setItem('api_host', cleanHost);
    // Automatically trigger fetch after saving
    setTimeout(() => fetchMessages(cleanHost), 100);
  };

  const fetchMessages = async (hostOverride?: string) => {
    setLoading(true);
    setErrorDetails(null);
    setIsDemoMode(false);

    // Determine the base URL: use override, or state, or default relative path
    const activeHost = hostOverride !== undefined ? hostOverride : apiHost;
    const baseUrl = activeHost || ''; 
    const targetPath = `${baseUrl}/api/get_messages.php`;

    // For debugging display
    const displayUrl = activeHost 
      ? targetPath 
      : `${window.location.origin}${targetPath}`;

    setDebugUrl(displayUrl);

    try {
      const response = await fetch(targetPath).catch(err => {
        // Handle Network Errors (often CORS when connecting to remote host)
        if (activeHost && err.message === 'Failed to fetch') {
           throw {
             type: 'cors',
             message: "Network Error: This is likely a CORS issue. Your Hostinger PHP script needs to allow connections from this dev environment."
           };
        }
        throw err;
      });

      // DIAGNOSTIC 1: Check if file exists (404 Error)
      if (response.status === 404) {

        // INTELLIGENT CHECK: Try to find 'setup_table.php' which we know works
        let setupFileExists = false;
        try {
            const checkSetup = await fetch(`${baseUrl}/api/setup_table.php`);
            if (checkSetup.status === 200) setupFileExists = true;
        } catch(e) {}

        if (setupFileExists) {
           throw { 
            type: 'file_missing', 
            message: "Database connected successfully (setup_table found), but 'get_messages.php' is missing." 
          };
        }

        throw { 
          type: '404', 
          message: `The file '${targetPath}' was not found.` 
        };
      }

      // DIAGNOSTIC 2: Check for Server Errors
      if (response.status === 500) {
        throw { 
          type: '500', 
          message: "Internal Server Error. The PHP script crashed." 
        };
      }

      const text = await response.text();

      // DIAGNOSTIC 3: Check if response is valid JSON
      let data;
      try {
        data = JSON.parse(text);
      } catch (e) {
        const preview = text.substring(0, 100).replace(/<[^>]*>?/gm, '');
        throw { 
          type: 'json', 
          message: `The server responded, but not with data. Response: "${preview}..."` 
        };
      }

      if (Array.isArray(data)) {
        setMessages(data);
      } else if (data.error) {
        // DIAGNOSTIC 4: Specific Database Auth Error
        if (data.error.includes("Access denied")) {
           throw { type: 'db_auth', message: data.error };
        }
        throw { type: 'unknown', message: data.error };
      } else {
        setMessages([]);
      }

    } catch (err: any) {
      console.warn("API Connection Issue:", err);

      if (err.type) {
        setErrorDetails(err);
      } else {
        setErrorDetails({ type: 'unknown', message: err.message || "Unknown connectivity error" });
      }

      setMessages(MOCK_MESSAGES);
      setIsDemoMode(true);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchMessages();
  }, []);

  return (
    <div className="pt-20 min-h-screen bg-slate-50">
      <div className="bg-slate-900 text-white py-12">
        <div className="max-w-7xl mx-auto px-4 flex justify-between items-center">
          <div>
            <h1 className="text-3xl font-black mb-2">Admin Dashboard</h1>
            <p className="text-slate-400">View incoming inquiries from the contact form.</p>
          </div>
          <div className="flex gap-3">
             {isDevEnvironment && (
               <button 
                onClick={() => setShowConfig(!showConfig)}
                className="flex items-center bg-slate-800 hover:bg-slate-700 px-4 py-2 rounded-lg font-bold transition-colors border border-slate-700"
               >
                 <Settings size={18} className="mr-2" />
                 Config
               </button>
             )}
            <button 
              onClick={() => fetchMessages()} 
              className="flex items-center bg-blue-600 hover:bg-blue-700 px-4 py-2 rounded-lg font-bold transition-colors"
            >
              <RefreshCw size={18} className={`mr-2 ${loading ? 'animate-spin' : ''}`} />
              Refresh
            </button>
          </div>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-4 -mt-8">

        {/* DEV ENVIRONMENT CONFIG PANEL */}
        {showConfig && (
          <div className="bg-white border-b-4 border-blue-500 p-6 rounded-xl shadow-xl mb-8 animate-fade-in-up">
            <h3 className="text-xl font-black text-slate-900 mb-2 flex items-center">
               <Globe className="mr-2 text-blue-500" /> Connect to Live Backend
            </h3>
            <p className="text-slate-600 mb-4">
              You are running in a <strong>Preview Environment</strong>. PHP files cannot run here. 
              Enter your hosted domain to fetch data from your live website.
            </p>
            <div className="flex gap-4">
              <div className="flex-grow">
                <input 
                  type="text" 
                  placeholder="https://promarchconsulting.co.uk" 
                  defaultValue={apiHost}
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none font-medium"
                  onKeyDown={(e) => {
                    if (e.key === 'Enter') saveApiHost(e.currentTarget.value);
                  }}
                  onBlur={(e) => saveApiHost(e.target.value)}
                />
                <p className="text-xs text-slate-400 mt-2">Enter the full URL of your Hostinger website (including https://)</p>
              </div>
              <button 
                onClick={() => fetchMessages()}
                className="bg-slate-900 text-white px-6 rounded-lg font-bold hover:bg-slate-800 h-[50px]"
              >
                Save & Connect
              </button>
            </div>
          </div>
        )}

        {/* DIAGNOSTIC ERROR BANNERS */}
        {errorDetails && (
          <div className="mb-8 space-y-4">

            {/* CORS ERROR */}
            {errorDetails.type === 'cors' && (
              <div className="bg-orange-50 border border-orange-200 p-6 rounded-xl shadow-lg">
                 <div className="flex items-start">
                  <Globe size={32} className="text-orange-600 mr-4 mt-1 flex-shrink-0" />
                  <div>
                    <h3 className="text-lg font-black text-orange-800 mb-1">Cross-Origin (CORS) Error</h3>
                    <p className="text-orange-700 mb-3">
                      We tried to connect to <strong>{apiHost}</strong>, but the server blocked the request.
                    </p>
                    <div className="bg-white p-4 rounded-lg border border-orange-200 text-sm">
                      <p className="font-bold text-slate-700 mb-2">Fix: Add this to the top of your PHP files on Hostinger:</p>
                      <code className="block bg-slate-900 text-green-400 p-3 rounded font-mono overflow-x-auto">
                        &lt;?php<br/>
                        header("Access-Control-Allow-Origin: *");<br/>
                        header("Access-Control-Allow-Headers: Content-Type");<br/>
                        // ... rest of your code
                      </code>
                    </div>
                  </div>
                 </div>
              </div>
            )}

            {/* SPECIFIC FILE MISSING ERROR (Database IS working) */}
            {errorDetails.type === 'file_missing' && (
              <div className="bg-green-50 border border-green-200 p-6 rounded-xl shadow-lg relative overflow-hidden">
                <div className="absolute top-0 right-0 p-4 opacity-10">
                    <CheckCircle size={100} className="text-green-600" />
                </div>
                <div className="flex items-start relative z-10">
                  <CheckCircle size={32} className="text-green-600 mr-4 mt-1 flex-shrink-0" />
                  <div>
                    <h3 className="text-lg font-black text-green-800 mb-1">Great News: Database Connected!</h3>
                    <p className="text-green-700 mb-3">
                      We found <code>setup_table.php</code>, which means your database username/password are correct!
                    </p>

                    <div className="bg-white/80 p-4 rounded-lg border border-green-200">
                        <h4 className="font-bold text-slate-800 text-sm mb-2 flex items-center">
                            <AlertCircle size={14} className="mr-2 text-orange-500" />
                            Remaining Issue: File Name
                        </h4>
                        <p className="text-sm text-slate-600 mb-2">
                           Although setup works, <code>get_messages.php</code> is still missing or named incorrectly.
                        </p>
                         <ul className="list-disc list-inside text-sm text-slate-700 font-medium space-y-1">
                            <li>Go to Hostinger File Manager.</li>
                            <li>Check if you renamed <code>get_messages</code> to <code>get_messages.php</code></li>
                            <li>Check for typos (e.g. <code>get_message.php</code> missing the 's')</li>
                        </ul>
                    </div>
                  </div>
                </div>
              </div>
            )}

             {/* 404 FILE MISSING ERROR */}
            {errorDetails.type === '404' && (
              <div className="bg-red-50 border border-red-200 p-6 rounded-xl shadow-lg">
                <div className="flex items-start">
                  <FileQuestion size={32} className="text-red-600 mr-4 mt-1 flex-shrink-0" />
                  <div>
                    <h3 className="text-lg font-black text-red-700 mb-1">API File Not Found (404)</h3>
                    <p className="text-red-600 mb-2">The request failed. We tried to reach:</p>

                    {/* Debug URL Section */}
                    <div className="bg-white p-3 rounded-lg border border-red-100 mb-4">
                      <code className="block bg-slate-50 p-2 rounded text-slate-800 text-sm font-mono break-all border border-slate-200">
                        {debugUrl}
                      </code>
                    </div>

                    {!apiHost && isDevEnvironment && (
                       <div className="mb-4 bg-yellow-100 border-l-4 border-yellow-500 p-4 text-yellow-800">
                         <strong>Tip:</strong> You are in a dev environment. Use the <strong>Config</strong> button above to connect to your real Hostinger domain.
                       </div>
                    )}

                    <h4 className="font-bold text-red-800 text-sm mb-2">How to verify:</h4>
                    <div className="flex gap-3 mb-4">
                       <a 
                        href={debugUrl} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="bg-red-600 text-white px-4 py-2 rounded-lg text-sm font-bold flex items-center hover:bg-red-700 transition-colors"
                       >
                         Click to Open File Directly <ExternalLink size={14} className="ml-2" />
                       </a>
                    </div>
                  </div>
                </div>
              </div>
            )}

            {/* WRONG PASSWORD ERROR */}
            {errorDetails.type === 'db_auth' && (
              <div className="bg-red-50 border border-red-200 p-6 rounded-xl flex items-start shadow-lg">
                <Lock size={32} className="text-red-600 mr-4 mt-1 flex-shrink-0" />
                <div>
                  <h3 className="text-lg font-black text-red-700 mb-1">Database Access Denied</h3>
                  <p className="text-red-600 mb-2">
                    The file exists (Good!), but the password or username in <code>db_connect.php</code> is wrong.
                  </p>
                  <div className="bg-white p-3 rounded border border-red-100 text-xs font-mono text-red-500 mb-3">
                    {errorDetails.message}
                  </div>
                  <h4 className="font-bold text-red-800 text-sm mb-1">How to fix in Hostinger:</h4>
                  <ol className="list-decimal list-inside text-sm text-red-700 font-medium space-y-1">
                    <li>Go to Hostinger Dashboard {'>'} Databases.</li>
                    <li>Note the <strong>Database Name</strong> and <strong>Database User</strong>.</li>
                    <li>If you don't know the password, change it in Hostinger.</li>
                    <li>Open <code>api/db_connect.php</code> and update <code>$pass</code>.</li>
                  </ol>
                </div>
              </div>
            )}

            {(errorDetails.type === '500' || errorDetails.type === 'json' || errorDetails.type === 'unknown') && (
               <div className="bg-yellow-50 border border-yellow-200 p-6 rounded-xl flex items-start shadow-lg">
                <AlertCircle size={32} className="text-yellow-600 mr-4 mt-1 flex-shrink-0" />
                <div>
                  <h3 className="text-lg font-black text-yellow-800 mb-1">Connection Error</h3>
                  <p className="text-yellow-700 text-sm mb-2">{errorDetails.message}</p>
                </div>
              </div>
            )}
          </div>
        )}

        {/* Demo Mode Notice */}
        {isDemoMode && (
          <div className="bg-blue-50 border border-blue-200 text-blue-800 p-4 rounded-xl flex items-center mb-8 shadow-sm">
            <Info size={20} className="mr-2 flex-shrink-0" />
            <span className="font-medium text-sm">
              <strong>Demo Mode Active:</strong> Showing sample data because the live connection failed. Fix the issues above to see real data.
            </span>
          </div>
        )}

        {/* DATA TABLE */}
        {loading && !messages.length ? (
          <div className="bg-white p-20 rounded-xl shadow-sm text-center">
            <Loader2 size={40} className="animate-spin text-blue-600 mx-auto mb-4" />
            <p className="text-slate-500 font-bold">Checking connection...</p>
          </div>
        ) : (
          <div className="bg-white rounded-2xl shadow-xl overflow-hidden border border-slate-100">
            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse">
                <thead>
                  <tr className="bg-slate-50 border-b border-slate-200">
                    <th className="p-5 text-xs font-black uppercase tracking-widest text-slate-500">Date</th>
                    <th className="p-5 text-xs font-black uppercase tracking-widest text-slate-500">From</th>
                    <th className="p-5 text-xs font-black uppercase tracking-widest text-slate-500">Subject</th>
                    <th className="p-5 text-xs font-black uppercase tracking-widest text-slate-500">Message</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {messages.length === 0 ? (
                    <tr>
                      <td colSpan={4} className="p-12 text-center text-slate-500 font-medium">
                        No messages found. Test the contact form to see data here.
                      </td>
                    </tr>
                  ) : (
                    messages.map((msg) => (
                      <tr key={msg.id} className="hover:bg-blue-50/50 transition-colors">
                        <td className="p-5 whitespace-nowrap text-sm text-slate-500">
                          <div className="flex items-center">
                            <Calendar size={14} className="mr-2 text-slate-400" />
                            {new Date(msg.created_at).toLocaleDateString()}
                            <span className="ml-2 text-xs opacity-60">{new Date(msg.created_at).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                          </div>
                        </td>
                        <td className="p-5">
                          <div className="font-bold text-slate-900">{msg.name}</div>
                          <a href={`mailto:${msg.email}`} className="text-sm text-blue-600 flex items-center hover:underline mt-1">
                            <Mail size={12} className="mr-1" /> {msg.email}
                          </a>
                        </td>
                        <td className="p-5">
                          <span className="inline-block px-3 py-1 bg-slate-100 rounded-full text-xs font-bold text-slate-700">
                            {msg.subject}
                          </span>
                        </td>
                        <td className="p-5 max-w-md">
                          <p className="text-slate-600 text-sm leading-relaxed">{msg.message}</p>
                        </td>
                      </tr>
                    ))
                  )}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

